module signal_generator(
    input clk,
    input rst_n,
    output reg [4:0] wave
);

    reg up;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wave <= 5'd0;
            up <= 1'b1;
        end
        else begin
            if (up) begin
                if (wave == 5'd31)
                    up <= 1'b0;
                else
                    wave <= wave + 1'b1;
            end
            else begin
                if (wave == 5'd0)
                    up <= 1'b1;
                else
                    wave <= wave - 1'b1;
            end
        end
    end

endmodule
